UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('d0760c52-c3a7-406f-9c8e-224831357ba6'::uuid, 'La rhinite aiguë sollicite le système immunitaire, la vitamine D3 soutient l''immunité innée pour une meilleure résistance aux infections.'),('594029a4-3b89-4e9b-b7f9-396420c66755'::uuid, 'La rhinite allergique est une réaction inflammatoire, l''antihistaminique bloque l''histamine pour réduire les symptômes efficacement.'),('8af471c1-ec2c-4d90-8042-3e4708cda391'::uuid, 'La rhinite allergique cause une inflammation locale, le corticoïde nasal réduit cette inflammation pour décongestionner durablement.'),('bca86e63-cd0a-4a58-9534-d22261c9a5e2'::uuid, 'L''allergie provoque un dépôt d''allergènes sur la muqueuse, le sérum physiologique rince délicatement le nez pour éliminer les irritants.'),('dabdaf44-8ccf-4d6b-a492-b6a22ea9add4'::uuid, 'La rhinopharyngite entraîne un excès de mucosités, le spray eau de mer isotonique aide à nettoyer le nez pour une meilleure respiration.'),('6a0ac7ff-49d7-4978-90fa-38260b1f60fb'::uuid, 'La rhinopharyngite s''accompagne souvent d''irritation de la gorge, ces pastilles adoucissent la muqueuse pour calmer la toux sèche.'),('17f0e0f7-b291-4830-9eef-9376dfaae247'::uuid, 'La rhinopharyngite sollicite les défenses immunitaires, la vitamine C renforce l''immunité pour soutenir la récupération de l''organisme.'),('bb7d426d-a389-4a32-8d01-f06bc21a3c29'::uuid, 'Le rhume provoque une congestion nasale, le spray hypertonique draine l''excès de liquide de la muqueuse pour libérer le nez.'),('d6566a73-f1c8-4d3e-ad92-05183d07c96f'::uuid, 'Le rhume se manifeste par un nez bouché, l''eau de mer hypertonique aide à décongestionner naturellement la muqueuse nasale pour une meilleure respiration.'),('214030e3-9444-48e8-8a33-c9f949a38827'::uuid, 'Les infections rhinopharyngées affaiblissent la gorge, le spray propolis possède des propriétés antiseptiques pour apaiser les irritations.'),('cce887fc-d0a7-4b83-bc84-73cccab87b76'::uuid, 'La rosacée se caractérise par une inflammation et des rougeurs cutanées, cette crème apaisante aide à réduire la réactivité de la peau.'),('c42a9741-175a-4c99-ba7b-ec2a7fd5bdf2'::uuid, 'La rosacée rend la peau plus sensible et réactive, cette crème protectrice renforce la barrière cutanée pour atténuer les rougeurs.'),('0d0090dc-7f18-41c4-8737-d5a3e92abff8'::uuid, 'La rosacée entraîne une hyper-réactivité cutanée, l''eau thermale, riche en minéraux, apaise l''inflammation pour calmer les rougeurs.'),('a03fedbe-33eb-412d-86c3-eee6ac80c747'::uuid, 'La schizophrénie nécessite une prise médicamenteuse régulière, ce pilulier aide à organiser le traitement pour optimiser l''observance.'),('395f841b-f01b-4fcb-96b7-e2443659d079'::uuid, 'La schizophrénie peut entraîner un déséquilibre du système nerveux, le magnésium et la B6 contribuent à la fonction psychologique normale.'),('c12a2ae8-aa61-48e2-abf2-d1b5f882debd'::uuid, 'La schizophrénie est associée à des anomalies cérébrales, les Oméga-3 ont un effet neuroprotecteur pour soutenir la fonction cognitive.'),('b67a71aa-f7f2-4ced-b50a-1d51cd0a308b'::uuid, 'La sciatique est caractérisée par une inflammation nerveuse, l''ibuprofène réduit cette inflammation pour soulager la douleur.'),('a7338494-dec8-4c57-b832-c186d809e5db'::uuid, 'La sciatique est causée par une compression nerveuse douloureuse, le patch chauffant détend les muscles environnants pour apaiser la tension.'),('61705d8f-644a-436a-bee8-2e5576f8b5d6'::uuid, 'La sciatique est souvent aggravée par une mauvaise posture, le coussin ergonomique corrige l''alignement de la colonne pour réduire la pression nerveuse.'),('760f4385-7056-4896-bc1d-f11588a74f09'::uuid, 'La sécheresse cutanée est due à un manque d''hydratation, cette crème émolliente nourrit intensément la peau pour restaurer sa souplesse.'),('ba6e1246-f5a3-416b-892f-ffbca59bb073'::uuid, 'La sécheresse cutanée altère la barrière épidermique, cette crème hydratante riche restaure le film hydrolipidique pour protéger la peau.'),('b537a3d0-fd0e-443c-a512-fda077342889'::uuid, 'La sécheresse cutanée est due à une perte d''eau transépidermique, cette crème émolliente riche renforce la barrière cutanée pour retenir l''hydratation.'),('8e2344a3-65ce-4a21-aa36-77d953e69a0d'::uuid, 'La sécheresse nasale irrite la muqueuse, le sérum physiologique hydrate et nettoie les fosses nasales pour restaurer le film protecteur.'),('99db32cd-e161-4d90-be29-6a0444ca1bfc'::uuid, 'La sécheresse nasale irrite la muqueuse, cette pommade aide à hydrater et restaurer la barrière protectrice.'),('f6c9e4ee-8001-4bb8-b746-f7c3c06a68e9'::uuid, 'La sécheresse nasale provoque des irritations, le sérum physiologique aide à nettoyer et humidifier la muqueuse nasale.'),('1187e579-c85e-4c8b-890a-cbb4ac6dbf1e'::uuid, 'La sécheresse oculaire réduit le film lacrymal, les larmes artificielles à base d''hyaluronate hydratent intensément la surface oculaire.'),('827e3d5b-6d54-487b-8f30-873e3307f197'::uuid, 'La sécheresse oculaire altère le film lacrymal, ce collyre aide à stabiliser l''hydratation et protéger la surface de l''œil.'),('34947f3b-9679-492f-8917-4a3c63b8f2d4'::uuid, 'La sécheresse oculaire est liée à une instabilité du film lacrymal, les Oméga-3 aident à améliorer sa qualité et sa stabilité.'),('b751ff02-c89f-4abd-b0dc-bcb3048837ee'::uuid, 'La sécheresse vaginale entraîne des irritations, ce gel hydratant aide à restaurer l''hydratation de la muqueuse et l''élasticité.'),('d255bd36-c637-4f7d-b3c9-62568ddeab82'::uuid, 'La sécheresse vaginale provoque une fragilisation de la muqueuse, ce gel à l''acide hyaluronique aide à hydrater et apaiser localement.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;